import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

export default function Home() {

  const nav = useNavigate();

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.hero}>

        {/* LEFT */}

        <div style={styles.left}>

          <p style={styles.tag}>
            Trusted Daily Worker Platform
          </p>

          <h1 style={styles.title}>
            Find Skilled Workers
            <br />
            Near You
          </h1>

          <p style={styles.subtitle}>
            Hire trusted labour workers easily for
            daily jobs and services.
          </p>

          <div style={styles.buttons}>

            <button
              style={styles.loginBtn}
              onClick={() => nav("/login")}
            >
              Login
            </button>

            <button
              style={styles.registerBtn}
              onClick={() => nav("/register")}
            >
              Register
            </button>

          </div>

        </div>

        {/* RIGHT */}

        <div style={styles.right}>

          <div style={styles.card}>

            <div style={styles.worker}>
              ⚡ Electrician
            </div>

            <div style={styles.worker}>
              🚿 Plumber
            </div>

            <div style={styles.worker}>
              🎨 Painter
            </div>

            <div style={styles.worker}>
              🪚 Carpenter
            </div>

          </div>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    fontFamily: "Arial, sans-serif"
  },

  hero: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "80px",
    gap: "40px"
  },

  left: {
    flex: 1
  },

  tag: {
    color: "#2563eb",
    fontWeight: "600",
    marginBottom: "15px"
  },

  title: {
    fontSize: "58px",
    lineHeight: "72px",
    color: "#111827",
    marginBottom: "20px"
  },

  subtitle: {
    color: "#6b7280",
    fontSize: "18px",
    lineHeight: "30px",
    maxWidth: "500px",
    marginBottom: "35px"
  },

  buttons: {
    display: "flex",
    gap: "15px"
  },

  loginBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px 28px",
    borderRadius: "10px",
    cursor: "pointer",
    fontSize: "15px"
  },

  registerBtn: {
    background: "white",
    color: "#111827",
    border: "1px solid #d1d5db",
    padding: "14px 28px",
    borderRadius: "10px",
    cursor: "pointer",
    fontSize: "15px"
  },

  right: {
    flex: 1,
    display: "flex",
    justifyContent: "center"
  },

  card: {
    width: "320px",
    background: "white",
    padding: "30px",
    borderRadius: "18px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.06)"
  },

  worker: {
    background: "#f9fafb",
    padding: "16px",
    borderRadius: "10px",
    marginBottom: "14px",
    fontSize: "16px",
    color: "#374151"
  }

};
